#include <bits/stdc++.h>
using namespace std;
int s[5],t[5][21],ans[5],b[3];
void dfs(int num,int x){
    if(max(b[1],b[2])>=ans[num])
        return;
    if(x>s[num]){
        ans[num]=max(b[1],b[2]);
        return;
    }
    b[1]+=t[num][x];
    dfs(num,x+1);
    b[1]-=t[num][x],b[2]+=t[num][x];
    dfs(num,x+1);
    b[2]-=t[num][x];
}
int main(){
    for(int i=1;i<5;i++)
        scanf("%d",&s[i]);
    for(int i=1;i<5;i++)
        for(int j=1;j<=s[i];j++)
            scanf("%d",&t[i][j]);
    memset(ans,127,sizeof(ans));
    dfs(1,1);
    dfs(2,1);
    dfs(3,1);
    dfs(4,1);
    printf("%d",ans[1]+ans[2]+ans[3]+ans[4]);
    return 0;
}
